// ============================================
// FIXED: correct path is items[0].json.body.data
// not items[0].json.data
// ============================================

const body = items[0].json.body;
const data = body?.data;

// Safety check
if (!data) {
  return [{ json: { error: 'No data found in webhook payload' } }];
}

const transcript    = data.transcript || [];
const dynVars       = data.conversation_initiation_client_data
                          ?.dynamic_variables || {};
const analysis      = data.analysis || {};
const metadata      = data.metadata || {};

// ── Extract transfer tool data ──────────────────
const transferEntry = transcript.find(
  t => t.tool_calls?.some(tc => tc.tool_name === 'transfer_to_number')
);

const transferCall = transferEntry?.tool_calls?.find(
  tc => tc.tool_name === 'transfer_to_number'
);

const transferResultEntry = transcript.find(
  t => t.tool_results?.some(tr => tr.tool_name === 'transfer_to_number')
);

const transferResult = transferResultEntry?.tool_results?.find(
  tr => tr.tool_name === 'transfer_to_number'
);

// Parse transfer params
let transferParams = {};
try {
  transferParams = JSON.parse(transferCall?.params_as_json || '{}');
} catch(e) {}

// Parse transfer result
let transferResultParsed = {};
try {
  transferResultParsed = JSON.parse(transferResult?.result_value || '{}');
} catch(e) {}

const transferAttempted   = !!transferCall;
const transferFailed      = transferResult?.is_error === true;
const transferSucceeded   = transferAttempted && !transferFailed;
const transferError       = transferResultParsed?.error || '';
const transferredTo       = transferParams?.transfer_number || '';
const transferAgentMsg    = transferParams?.agent_message || '';

// ── Extract other tool results ──────────────────
const formStatusEntry = transcript.find(
  t => t.tool_calls?.some(tc => tc.tool_name === 'update_form_status')
);
const formStatusCall = formStatusEntry?.tool_calls?.find(
  tc => tc.tool_name === 'update_form_status'
);
let formStatusParams = {};
try {
  formStatusParams = JSON.parse(formStatusCall?.params_as_json || '{}');
} catch(e) {}

// ── Build clean output ──────────────────────────
return [{
  json: {

    // ── Call basics ──
    conversation_id:    data.conversation_id,
    call_duration_secs: metadata.start_time_unix_secs
                          ? (metadata.call_duration_secs || 0)
                          : 0,
    call_status:        analysis.call_successful,
    call_summary:       analysis.transcript_summary,
    termination_reason: metadata.termination_reason,

    // ── Lead / customer data ──
    lead_id:            dynVars.lead_uuid || dynVars.lead_id,
    customer_name:      dynVars.customer_name,
    customer_address:   dynVars.customer_address,
    customer_phone:     dynVars['system__caller_id'] || null,
    issue_description:  dynVars.issue_description,
    window_count:       dynVars.window_count,

    // ── Transfer data ──
    transfer_attempted:  transferAttempted,
    transfer_succeeded:  transferSucceeded,
    transfer_failed:     transferFailed,
    transfer_error:      transferError,
    transferred_to:      transferredTo,
    transfer_agent_msg:  transferAgentMsg,

    // ── Form status ──
    form_status:         formStatusParams.form_status || null,
    form_confirmed:      formStatusParams.form_status === 'confirmed',

    // ── Features used (from your data) ──
    transfer_feature_used: metadata.features_usage?.transfer_to_number?.used || false
  }
}];

const raw = $json.output || $json.text || $json.body || JSON.stringify($json);

let parsed = null;
try { parsed = JSON.parse(raw); } catch(e) {}

if (!parsed) {
  const s = String(raw).replace(/```(?:json)?\s*/gi,'').replace(/```\s*/g,'').trim();
  try { parsed = JSON.parse(s); } catch(e) {}
}

if (!parsed) {
  const m = String(raw).match(/\{[\s\S]*\}/);
  if (m) try { parsed = JSON.parse(m[0]); } catch(e) {}
}

if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
  throw new Error('AI parse failed. raw preview: ' + String(raw).substring(0, 300));
}

const s = v => (v != null && v !== '') ? v : '';
const n = v => (typeof v === 'number' && !isNaN(v)) ? v : 0;
const b = v => v === true;

return [{ json: {
