  conversion_probability:  n(parsed.conversion_probability),
  sales_readiness:         s(parsed.sales_readiness),
  follow_up_urgency_hours: n(parsed.follow_up_urgency_hours),
  recommended_action:      s(parsed.recommended_action),
  call_transfer_requested: b(parsed.call_transfer_requested),
  call_transfer_status:    s(parsed.call_transfer_status),
  form_submitted:          s(parsed.form_submitted),
  score_breakdown:         parsed.score_breakdown || { positive_signals: [], negative_signals: [] },
  reasoning:               s(parsed.reasoning),
