// ============================================================

// 👉 Current time (IST safe)
const now = new Date();

// 👉 Add 2 hours
const twoHoursLater = new Date(now.getTime() + 2 * 60 * 60 * 1000);

// Helper to normalize time (handles "09:00" & "09:00:00")
function normalizeTime(t) {
  return t.length === 5 ? t + ":00" : t;
}

// ============================================================
// FILTER LOGIC
// ============================================================

const filtered = items.filter(item => {
  const appt = item.json;

  if (!appt.appointment_date || !appt.appointment_time) return false;

  // 👉 Create datetime in IST
  const apptDateTime = new Date(
    `${appt.appointment_date}T${normalizeTime(appt.appointment_time)}+05:30`
  );

  if (isNaN(apptDateTime.getTime())) return false;

  return (
    apptDateTime.getTime() >= now.getTime() &&
    apptDateTime.getTime() <= twoHoursLater.getTime()
  );
});

// ============================================================
// REMOVE DUPLICATES
// ============================================================

const unique = [];
const seen = new Set();

for (const item of filtered) {
  const key = item.json.appointment_date + item.json.appointment_time;
  if (!seen.has(key)) {
    seen.add(key);
    unique.push(item);
  }
}

// ============================================================
// OUTPUT
