if (unique.length === 0) {
  return [{
    json: {
      skip: true,
      message: "No appointments in next 2 hours",
      current_time: now.toLocaleString("en-IN", { timeZone: "Asia/Kolkata" }),
      window_end: twoHoursLater.toLocaleString("en-IN", { timeZone: "Asia/Kolkata" })
    }
  }];
}

return unique;

const appt = items[0].json;

