// ============================================================
// PARSE & VALIDATE - Book Appointment (FIXED)
// ============================================================

// Safe body extraction
const body = $input.item.json.body ?? $input.item.json ?? {};

// Extract fields safely
const lead_id          = (body.lead_id ?? '').toString().trim();
let appointment_date = (body.appointment_date ?? '').toString().trim();
const appointment_time = (body.appointment_time ?? '').toString().trim();
const service_type     = (body.service_type ?? 'Quote Review Call').toString().trim();
const notes            = (body.notes ?? '').toString().trim();
const customer_name    = (body.customer_name ?? '').toString().trim();
const customer_email   = (body.email ?? '').toString().trim();
const customer_phone   = (body.customer_phone ?? '').toString().trim();
const customer_address = (body.customer_address ?? '').toString().trim();

// ============================================================
// VALIDATION (ONLY REQUIRED FIELDS)
// ============================================================

const missing = [];

if (!appointment_date)  missing.push('appointment_date');
if (!appointment_time)  missing.push('appointment_time');
if (!customer_email)    missing.push('customer_email');

// Past-date validation — auto-correct year if LLM used wrong year (e.g. 2024 instead of 2026)
const today = new Date().toISOString().split('T')[0];
if (appointment_date && appointment_date < today) {
  const dateParts = appointment_date.split('-');
  const currentYear = new Date().getFullYear();
  const sameMonthDay = `${currentYear}-${dateParts[1]}-${dateParts[2]}`;
  if (sameMonthDay >= today) {
    appointment_date = sameMonthDay;
  } else {
    const nextYearDate = `${currentYear + 1}-${dateParts[1]}-${dateParts[2]}`;
    if (nextYearDate >= today) {
      appointment_date = nextYearDate;
    } else {
      return [{ json: { valid: false, error: 'Appointment date cannot be in the past.', missing_fields: [], received: body } }];
    }
  }
}

if (missing.length > 0) {
  return [
    {
      json: {
        valid: false,
        error: 'Missing required fields: ' + missing.join(', '),
        missing_fields: missing,
        received: body
      }
    }
  ];
}

// ============================================================
// TIME PROCESSING
// ============================================================

// Build ISO start
const startISO = `${appointment_date}T${appointment_time}:00`;

// Safe time split
let endISO = startISO;

if (appointment_time.includes(':')) {
  const [h, m] = appointment_time.split(':').map(Number);

  if (!isNaN(h) && !isNaN(m)) {
    const endHour = String(h + 1).padStart(2, '0');
    endISO = `${appointment_date}T${endHour}:${String(m).padStart(2,'0')}:00`;
  }
}

// ============================================================
// SERVICE LABEL NORMALIZATION
// ============================================================

let serviceLabel = 'Quote Review Call';

if (service_type === 'On-Site Estimate') {
  serviceLabel = 'On-Site Estimate';
} else if (service_type === 'Callback - Scheduling') {
  serviceLabel = 'Callback - Scheduling';
} else if (service_type) {
  serviceLabel = service_type;
}

const serviceTypeDb = serviceLabel === 'Quote Review Call' ? 'quote_review_call' : (serviceLabel === 'Installation' ? 'installation' : 'estimating');

// ============================================================
// FINAL OUTPUT
// ============================================================

return [
  {
    json: {
      valid: true,

      // Core fields
      lead_id,
      appointment_date,
      appointment_time,
      customer_email,

      // Optional fields
      service_type: serviceLabel,
      service_type_db: serviceTypeDb,
      notes,
      customer_name,
      customer_phone,
      customer_address,

      // Time
      startISO,
      endISO,

      // Calendar
      calendar_summary: `Apex Windows - ${serviceLabel} - ${customer_name || customer_email}`,
      calendar_description:
        `Lead ID: ${lead_id || 'N/A'}\n` +
        `Service: ${serviceLabel}\n` +
        `Email: ${customer_email}\n` +
        `Phone: ${customer_phone}\n` +
