];

// ============================================================
// MERGE — works when Code node sits directly after Calendar node
// $input.first().json = Google Calendar event output
// ============================================================

const cal = $input.first().json;

const safe = (val) =>
  (val !== null && val !== undefined && val !== '')
    ? String(val).trim()
    : '';

// ── Calendar fields — all confirmed present in your output ──
const event_id     = safe(cal?.id);
const booking_link = safe(cal?.htmlLink);
const cal_status   = safe(cal?.status);
const cal_summary  = safe(cal?.summary);
const rawStart     = cal?.start?.dateTime || '';

// ── Parse date/time from ISO string "2026-04-18T00:30:00+05:30" ──
let appointment_date = '';
let appointment_time = '';

if (rawStart) {
  // Strip the timezone offset and parse directly
  const stripped = rawStart.replace(/([+-]\d{2}:\d{2}|Z)$/, '');
  const dt = new Date(stripped);
  const yyyy = dt.getFullYear();
  const mm   = String(dt.getMonth() + 1).padStart(2, '0');
  const dd   = String(dt.getDate()).padStart(2, '0');
  const hh   = String(dt.getHours()).padStart(2, '0');
  const min  = String(dt.getMinutes()).padStart(2, '0');
  appointment_date = `${yyyy}-${mm}-${dd}`;
  appointment_time = `${hh}:${min}`;
}

// ── Get booking data from the webhook trigger node ──
// Parse & Validate Booking is the webhook — always accessible
const parsed = $('Parse & Validate Booking').first().json;

const lead_id        = safe(parsed?.lead_id);
const client_name    = safe(parsed?.customer_name);
const client_email   = safe(parsed?.customer_email);
const client_phone   = safe(parsed?.customer_phone);
const client_address = safe(parsed?.customer_address);
const service_type   = safe(parsed?.service_type);
const notes          = safe(parsed?.notes);
const final_date     = safe(parsed?.appointment_date) || appointment_date;
const final_time     = safe(parsed?.appointment_time) || appointment_time;

// ── Debug dump so you can see exactly what arrived ──
// Remove after confirmed working
const debug = {
  cal_keys:    Object.keys(cal || {}),
  parsed_keys: Object.keys(parsed || {}),
  rawStart,
  lead_id,
  client_email
};

if (!client_email) {
  throw new Error(
    `No email found. parsed keys: ${debug.parsed_keys.join(', ')} | ` +
    `lead_id: "${lead_id}" | rawStart: "${rawStart}"`
  );
}

return [{
  json: {
    client_email,
    client_phone,
    service_type,
    service_type_db: safe(parsed?.service_type_db) || 'estimating',
    notes,
    appointment_date: final_date,
    appointment_time: final_time,
    event_id,
    booking_link,
    cal_status,
    cal_summary,
    booked_at:  new Date().toISOString(),
    timezone:   cal?.start?.timeZone || 'America/New_York',
    _debug:     debug
  }
}];

// Build success response for ElevenLabs / calling agent
const d = $('Merge Booking Data').item.json;
const name = $('Parse & Validate Booking').item.json.customer_name || 'customer';

return [{
  json: {
    success: true,
    message: `Appointment booked for ${name} on ${d.appointment_date} at ${d.appointment_time}`,
    appointment_date: d.appointment_date,
    appointment_time: d.appointment_time,
    service_type:     d.service_type,
    booking_link:     d.booking_link,
    email_sent:       true
  }
}];

// ---- ERROR RESPONSE BUILDER ----
const err = $input.item.json;
return [{
  json: {
    success: false,
    error: err.error || 'Validation failed',
    missing_fields: err.missing_fields || [],
    received: err.received || {}
  }
}];

// ============================================================
// PARSE AVAILABILITY REQUEST — IST AWARE
// Input:  { date?: 'YYYY-MM-DD', lead_id?: string }
// Output: { valid, lead_id, date_from (ISO), date_to (ISO) }
// All logic done in IST (UTC+5:30)
// ============================================================

const IST_OFFSET_MS = 5.5 * 60 * 60 * 1000; // 19800000 ms

// Helper: get current time in IST as a plain object
function nowIST() {
  const nowUtc = Date.now();
  return new Date(nowUtc + IST_OFFSET_MS);
}

// Helper: build a UTC timestamp for a given IST date+hour+minute
function istToUtcMs(year, month, day, hour, minute) {
  // month is 0-indexed
  const utcMs = Date.UTC(year, month, day, hour, minute, 0, 0) - IST_OFFSET_MS;
  return utcMs;
}

const body   = $input.item.json.body || $input.item.json;
const rawDate = (body.date || body.date_from || '').toString().trim();
const lead_id = (body.lead_id || '').toString().trim();

// ── Determine start date in IST ───────────────────────────────
let istYear, istMonth, istDay;

if (rawDate && /^\d{4}-\d{2}-\d{2}$/.test(rawDate)) {
  const parts = rawDate.split('-').map(Number);
  istYear  = parts[0];
  istMonth = parts[1] - 1; // 0-indexed
  istDay   = parts[2];

  // Auto-correct: if parsed date is in the past (e.g. LLM sent 2024 instead of 2026), default to today
  const parsedUtcMs = Date.UTC(istYear, istMonth, istDay);
  const nCheck = nowIST();
  const todayUtcMs = Date.UTC(nCheck.getUTCFullYear(), nCheck.getUTCMonth(), nCheck.getUTCDate());
  if (parsedUtcMs < todayUtcMs) {
    istYear  = nCheck.getUTCFullYear();
    istMonth = nCheck.getUTCMonth();
    istDay   = nCheck.getUTCDate();
  }
} else {
  // Use today in IST
  const n = nowIST();
  istYear  = n.getUTCFullYear();
  istMonth = n.getUTCMonth();
  istDay   = n.getUTCDate();
}

// ── Push to next weekday if weekend ──────────────────────────
// Build a temporary date to check day-of-week
let checkDate = new Date(Date.UTC(istYear, istMonth, istDay, 0, 0, 0));
let dow = checkDate.getUTCDay();
if (dow === 6) { checkDate.setUTCDate(checkDate.getUTCDate() + 2); } // Sat → Mon
if (dow === 0) { checkDate.setUTCDate(checkDate.getUTCDate() + 1); } // Sun → Mon

istYear  = checkDate.getUTCFullYear();
istMonth = checkDate.getUTCMonth();
istDay   = checkDate.getUTCDate();

// ── Build from/to as UTC timestamps representing IST 08:00 / 18:00 ──
// from = requested date 08:00 IST
// to   = requested date + 5 days 18:00 IST
const fromUtcMs = istToUtcMs(istYear, istMonth, istDay, 8, 0);
const toDate    = new Date(Date.UTC(istYear, istMonth, istDay + 5, 18, 0, 0, 0));
const toUtcMs   = toDate.getTime() - IST_OFFSET_MS;

return [{
  json: {
    valid:     true,
    lead_id,
    date_from: new Date(fromUtcMs).toISOString(),
    date_to:   new Date(toUtcMs).toISOString(),
    // Pass IST date components for slot generator
    ist_start_year:  istYear,
    ist_start_month: istMonth,
    ist_start_day:   istDay
  }
}];

// ============================================================
// BUILD AVAILABLE SLOTS — IST TIMEZONE CORRECT
// 
// KEY FIX: All slot generation and comparison happens in IST.
// Google Calendar returns events with timezone offsets (+05:30).
// We must parse those correctly and compare in IST space.
// ============================================================

const IST_OFFSET_MS = 5.5 * 60 * 60 * 1000;

// Convert any datetime string to UTC milliseconds correctly
// Works with: '2026-04-21T08:00:00.000Z' OR '2026-04-17T18:30:00+05:30'
function toUtcMs(dateStr) {
  return new Date(dateStr).getTime(); // JS Date handles tz offsets natively
}

// Convert UTC ms → IST hour (0-23)
function utcMsToISTHour(ms) {
  return new Date(ms + IST_OFFSET_MS).getUTCHours();
}

// Convert UTC ms → IST day-of-week (0=Sun,6=Sat)
function utcMsToISTDow(ms) {
  return new Date(ms + IST_OFFSET_MS).getUTCDay();
}

// Convert UTC ms → IST date string YYYY-MM-DD
function utcMsToISTDate(ms) {
  const d = new Date(ms + IST_OFFSET_MS);
  return `${d.getUTCFullYear()}-${String(d.getUTCMonth()+1).padStart(2,'0')}-${String(d.getUTCDate()).padStart(2,'0')}`;
}

// Get IST components from UTC ms
function getISTComponents(ms) {
  const d = new Date(ms + IST_OFFSET_MS);
  return {
    year:    d.getUTCFullYear(),
    month:   d.getUTCMonth(),   // 0-indexed
    day:     d.getUTCDate(),
    hour:    d.getUTCHours(),
    minute:  d.getUTCMinutes(),
    dow:     d.getUTCDay()
  };
}

// Build UTC ms from IST components (year, month 0-indexed, day, hour, min)
function istComponentsToUtcMs(year, month, day, hour, minute) {
  return Date.UTC(year, month, day, hour, minute, 0, 0) - IST_OFFSET_MS;
}

// ── 1. Get parsed range ───────────────────────────────────────
const parsed  = $('Parse Availability Request').item.json;
const lead_id = parsed.lead_id || '';

const fromUtcMs = toUtcMs(parsed.date_from);
const toUtcMs_  = toUtcMs(parsed.date_to);

// Current time in UTC ms
const nowUtcMs = Date.now();

// ── 2. Build busy windows from Google Calendar ────────────────
const allItems = $input.all();
const seen = new Set();
const busyWindows = [];

for (const item of allItems) {
  const e = item.json;
  if (!e.start) continue;

  // Handle both dateTime events and all-day (date-only) events
  const startStr = e.start.dateTime || e.start.date;
  const endStr   = e.end.dateTime   || e.end.date;
  if (!startStr || !endStr) continue;

  const startMs = toUtcMs(startStr);
  const endMs   = toUtcMs(endStr);
  const key     = `${startMs}-${endMs}`;

  if (seen.has(key)) continue;
  seen.add(key);

  busyWindows.push({ start: startMs, end: endMs });
}

// Overlap checker
function isBooked(slotStartMs, slotEndMs) {
  return busyWindows.some(b => slotStartMs < b.end && slotEndMs > b.start);
}

// ── 3. Generate 1-hour slots Mon-Fri 08:00-18:00 IST ─────────
const slots  = [];
const DAYS   = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

// Start cursor at fromDate components in IST
let { year: cy, month: cm, day: cd } = getISTComponents(fromUtcMs);
let currentHour = 8; // Start at 08:00 IST

// Safety limit: max 14 days scan
const maxDays = 14;
let daysScanned = 0;

while (slots.length < 8 && daysScanned < maxDays) {

  // Build slot start in UTC ms
  const slotStartMs = istComponentsToUtcMs(cy, cm, cd, currentHour, 0);
  const slotEndMs   = istComponentsToUtcMs(cy, cm, cd, currentHour + 1, 0);

  const dow = utcMsToISTDow(slotStartMs);

  // Skip weekends
  if (dow === 0 || dow === 6) {
    // Move to next day at 08:00
    cd++;
    currentHour = 8;
    daysScanned++;
    continue;
  }

  // Past 6pm IST → next day
  if (currentHour >= 18) {
    cd++;
    currentHour = 8;
    daysScanned++;
    continue;
  }

  // Skip past slots (already happened)
  if (slotStartMs <= nowUtcMs) {
    currentHour++;
    continue;
  }

  // Skip if outside our requested range
  if (slotStartMs > toUtcMs_) break;

  // Skip if booked
  if (!isBooked(slotStartMs, slotEndMs)) {
    const h    = currentHour;
    const ampm = h >= 12 ? 'PM' : 'AM';
    const h12  = h > 12 ? h - 12 : h === 0 ? 12 : h;
    const { day: labelDay, month: labelMonth } = getISTComponents(slotStartMs);
    const dowLabel = DAYS[dow];
    const monLabel = MONTHS[labelMonth];

    slots.push({
      label:     `${dowLabel}, ${monLabel} ${labelDay} at ${h12}:00 ${ampm}`,
      date:      utcMsToISTDate(slotStartMs),
      time:      `${String(h).padStart(2,'0')}:00`,
      iso_start: new Date(slotStartMs).toISOString(),
      iso_end:   new Date(slotEndMs).toISOString()
    });
  }

  currentHour++;
}

// ── 4. Return ─────────────────────────────────────────────────
const fromLabel = utcMsToISTDate(fromUtcMs);
const toLabel   = utcMsToISTDate(toUtcMs_);

return [{
  json: {
    success:          true,
    lead_id,
    slots_found:      slots.length,
    busy_slots_found: busyWindows.length,
    available_slots:  slots,
    slots_text: slots.map((s, i) => `Option ${i+1}: ${s.label}`).join('. '),
    message: slots.length > 0
      ? `Found ${slots.length} available slot(s) from ${fromLabel} to ${toLabel}`
      : `No available slots found between ${fromLabel} and ${toLabel}. Try different dates.`
  }
}];

