// Get raw text from LLM output
const text = $input.first().json.output?.[0]?.content?.[0]?.text || "";

// Default value
let formSubmitted = false;

// Try to extract JSON from text
try {
    const jsonMatch = text.match(/\{[\s\S]*\}/);

    if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0]);

        // Normalize key (handle spaces / casing issues)
        const value = parsed["form submitted"] || parsed["form_submitted"] || parsed["formSubmitted"];

        if (typeof value === "string") {
            formSubmitted = value.toLowerCase() === "true";
        } else if (typeof value === "boolean") {
            formSubmitted = value;
        }
    }
} catch (error) {
    // fallback: keyword check
    if (text.toLowerCase().includes('"form submitted":"true"')) {
        formSubmitted = true;
    }
}

// Return clean output
return [
  {
    json: {
      form_submitted: formSubmitted
    }
  }
];

